INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-d0d1b9a2-moex-00465', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-34c7f7f6', 'sub-elementary-d0d1b9a2-02', NULL, 'single_choice', '「心理學的研究上有個現象叫做『破窗效應』，就是說，一個房子如果窗戶破了，沒有人去 修補，隔不久，其它的窗戶也會莫名其妙的被人打破；一面牆，如果出現一些塗鴉沒有清洗 掉，很快地，牆上就布滿了亂七八糟，不堪入目的東西。一個很乾淨的地方，人會不好意思 丟垃圾，但是一旦地上有垃圾出現之後，人就會毫不猶疑地拋，絲毫不覺羞愧。這真是很奇 怪的現象。」 根據上文，下列選項何者符合「破窗效應」的觀點？', '["管理時必須有統一的要求與準則", "防微杜漸是預防問題的手段之一", "人們很容易仿效他人不良的行為", "組織中引進競爭者可以激發活力 環境對人的行為具有強烈誘導性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00466', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '下列關於期末結帳之敘述，何者正確？', '["結帳後預收收入帳戶餘額會歸零", "資產與負債項目皆須結帳", "累計折舊不須結帳", "利息費用不須結帳"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00467', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司X9年初於商店街承租店面一年，租約規定每月月初支付固定租金$150,000，另按全年公司營業額 超過$6,000,000部分的5%支付變動租金，並於次年度1月10日前支付。甲公司X9年度結算後全年營業 額為$8,000,000，則甲公司關於該租約於X9年底之應付租金為：', '["$0", "$7,500", "$100,000", "$150,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00468', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '一鳴公司期末調整前試算表用品盤存餘額$35,000，收入餘額$520,000 與費用餘額$264,000，須調整事項 為：尚未耗用的用品$20,000；已提供服務之預收收入$9,500；當期預期信用減損損失為$11,000；應計利 息費用$18,000；已耗用之預付保險費為$5,000；尚未提供服務之預收收入$80,000。則當期之淨利為何？ （不考慮所得稅）', '["$211,500", "$216,500", "$291,500", "$296,500"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00469', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '關於會計循環之步驟，下列敘述何者正確？', '["分錄→過帳→調整→結帳→試算→編表", "分錄→過帳→調整→試算→結帳→編表", "分錄→過帳→試算→調整→編表→結帳", "分錄→過帳→試算→編表→調整→結帳"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00470', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司X2年底應收帳款總額$300,000，其中過期1天至60天的帳款為$70,000，過期61天以上的帳款為 $30,000。調整前備抵損失為借餘$550，該公司估計未過期帳款的損失率為1%，過期1天至60天的帳款 損失率為10%，過期61天以上的帳款損失率為20%。則X2年度之預期信用減損損失為何？', '["$14,450", "$15,000", "$15,550", "$16,550"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00471', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司X1年5月31日銀行存款調節表中，未兌現支票$6,000，6月份公司開出支票$93,000，6月份銀行 對帳單部分資料包含：甲公司支票兌現$85,000，存款不足退票$2,000，銀行手續費$1,500，銀行託收票據 $600。試問6月份未兌現支票金額為何？', '["$14,000", "$10,500", "$2,000", "$10,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00472', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '下列何者交易發生時可能除列「應收帳款」或「應收票據」？', '["公司以應收帳款擔保借款", "公司以不具追索權之方式將應收帳款出售", "公司以具有追索權之方式將應收票據貼現", "公司約定將來以高於售價之固定價格買回之方式將應收帳款出售"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00473', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '有關存貨之會計處理，下列敘述何者錯誤？', '["存貨評價採先進先出法，期末存貨成本較接近期末存貨之市價", "對可替換之存貨項目採個別認定法將能夠操縱損益", "存貨期末評價需採成本與淨變現價值孰低法", "在物價上漲時，採加權平均法將產生較採先進先出法時為高之本期淨利"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00474', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-426aa0fd', 'sub-elementary-d0d1b9a2-03', NULL, 'single_choice', '甲公司X1年12月31日進行實地盤點後之存貨金額為$200,000。但此金額並未考慮以下事實：盤點的存 貨中包括乙公司寄銷之商品成本$35,000；起運點交貨的在途進貨之商品成本$40,000；目的地交貨的在途 銷貨之商品成本$60,000；寄銷在丙公司之商品成本$76,000，尚有一半未售出。請問甲公司X1年底存貨 應報導的金額為：', '["$183,000", "$243,000", "$303,000", "$341,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:47+00:00", "source_pdf_sha1": "c5115db7419f", "answer_pdf_sha1": "3f17411e8587", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL)
